<body>
<div id="desktop">
  <div class="topbar">
    <strong>Activities</strong>
    <div>Ubuntu Desktop</div>
    <div class="topbar-right"><span>◉</span><span>⌁</span><span id="clock"></span></div>
  </div>

  <div class="desktop-label">
    <div class="desktop-icon"></div>
    Home
  </div>

  <nav id="taskbar" aria-label="Application dock">
    <button id="open-files" class="launcher" title="Files" aria-label="Open Files">📁</button>
    <button id="open-notepad" class="launcher" title="Notepad" aria-label="Open Notepad">📝</button>
  </nav>

  <section id="files-window" class="window" aria-label="Files window">
    <div class="titlebar">
      <span class="window-title">Files</span>
      <div class="window-controls">
        <button class="win-control win-close" type="button" aria-label="Close Files">×</button>
      </div>
    </div>
    <div class="files-toolbar">
      <button id="files-up" type="button" title="Parent folder" aria-label="Go to parent folder">↑</button>
      <div id="files-path">/</div>
    </div>
    <div id="files-list" aria-label="Filesystem listing"></div>
  </section>

  <section id="notepad-window" class="window" aria-label="Notepad window">
    <div class="titlebar">
      <span class="window-title">Notepad</span>
      <div class="window-controls">
        <button class="win-control win-close" type="button" aria-label="Close Notepad">×</button>
      </div>
    </div>
    <div class="notepad-body">
      <div style="display:flex; min-height:42px; background:#252229;">
        <div id="tabs" aria-label="Notepad tabs"></div>
        <button id="new-tab" type="button" title="New tab" aria-label="Create new tab">+</button>
      </div>
      <textarea id="editor" aria-label="Text editor" spellcheck="true"></textarea>
    </div>
  </section>
</div>

<script>
(function () {
  const desktop = document.getElementById("desktop");
  const filesWindow = document.getElementById("files-window");
  const notepadWindow = document.getElementById("notepad-window");
  let highestZ = 10;

  function raiseWindow(win) {
    highestZ += 1;
    win.style.zIndex = highestZ;
    document.querySelectorAll(".window").forEach(w => w.classList.remove("active"));
    win.classList.add("active");
  }

  function showWindow(win) {
    win.style.display = "flex";
    raiseWindow(win);
  }

  document.getElementById("open-files").addEventListener("click", function () {
    showWindow(filesWindow);
  });

  document.getElementById("open-notepad").addEventListener("click", function () {
    showWindow(notepadWindow);
  });

  document.querySelectorAll(".window").forEach(function (win) {
    win.addEventListener("mousedown", function () {
      raiseWindow(win);
    });

    win.querySelector(".win-close").addEventListener("click", function (event) {
      event.stopPropagation();
      win.style.display = "none";
    });

    const titlebar = win.querySelector(".titlebar");
    titlebar.addEventListener("mousedown", function (event) {
      if (event.target.closest("button")) return;

      raiseWindow(win);
      const rect = win.getBoundingClientRect();
      const startX = event.clientX;
      const startY = event.clientY;
      const originalLeft = rect.left;
      const originalTop = rect.top;

      function move(eventMove) {
        const maxLeft = Math.max(0, window.innerWidth - 160);
        const maxTop = Math.max(34, window.innerHeight - 80);
        win.style.left = Math.max(0, Math.min(maxLeft, originalLeft + eventMove.clientX - startX)) + "px";
        win.style.top = Math.max(34, Math.min(maxTop, originalTop + eventMove.clientY - startY)) + "px";
      }

      function stop() {
        document.removeEventListener("mousemove", move);
        document.removeEventListener("mouseup", stop);
      }

      document.addEventListener("mousemove", move);
      document.addEventListener("mouseup", stop);
    });
  });

  const filesystem = {
    "/": [
      { name: "bin", type: "folder" },
      { name: "etc", type: "folder" },
      { name: "home", type: "folder" },
      { name: "usr", type: "folder" },
      { name: "var", type: "folder" },
      { name: "README.txt", type: "file" }
    ],
    "/bin": [
      { name: "bash", type: "file" },
      { name: "cat", type: "file" },
      { name: "ls", type: "file" }
    ],
    "/etc": [
      { name: "hostname", type: "file" },
      { name: "network", type: "folder" },
      { name: "os-release", type: "file" }
    ],
    "/etc/network": [
      { name: "interfaces", type: "file" }
    ],
    "/home": [
      { name: "user", type: "folder" }
    ],
    "/home/user": [
      { name: "Documents", type: "folder" },
      { name: "Downloads", type: "folder" },
      { name: "Pictures", type: "folder" },
      { name: "welcome.txt", type: "file" }
    ],
    "/home/user/Documents": [
      { name: "Projects", type: "folder" },
      { name: "notes.txt", type: "file" },
      { name: "report.odt", type: "file" }
    ],
    "/home/user/Documents/Projects": [
      { name: "desktop-app", type: "folder" },
      { name: "ideas.md", type: "file" }
    ],
    "/home/user/Documents/Projects/desktop-app": [
      { name: "app.html", type: "file" }
    ],
    "/home/user/Downloads": [
      { name: "ubuntu-wallpaper.jpg", type: "file" },
      { name: "archive.zip", type: "file" }
    ],
    "/home/user/Pictures": [
      { name: "Sunset.png", type: "file" },
      { name: "Vacation", type: "folder" }
    ],
    "/home/user/Pictures/Vacation": [
      { name: "mountains.jpg", type: "file" }
    ],
    "/usr": [
      { name: "bin", type: "folder" },
      { name: "share", type: "folder" }
    ],
    "/usr/bin": [
      { name: "python3", type: "file" },
      { name: "nano", type: "file" }
    ],
    "/usr/share": [
      { name: "applications", type: "folder" }
    ],
    "/usr/share/applications": [
      { name: "org.gnome.Files.desktop", type: "file" }
    ],
    "/var": [
      { name: "log", type: "folder" },
      { name: "tmp", type: "folder" }
    ],
    "/var/log": [
      { name: "syslog", type: "file" }
    ],
    "/var/tmp": []
  };

  const pathElement = document.getElementById("files-path");
  const filesList = document.getElementById("files-list");
  const filesUp = document.getElementById("files-up");
  let currentPath = "/";

  function childPath(parent, name) {
    return parent === "/" ? "/" + name : parent + "/" + name;
  }

  function parentPath(path) {
    if (path === "/") return "/";
    const parts = path.split("/").filter(Boolean);
    parts.pop();
    return parts.length ? "/" + parts.join("/") : "/";
  }

  function renderFiles() {
    pathElement.textContent = currentPath;
    filesUp.disabled = currentPath === "/";
    filesList.innerHTML = "";

    const items = filesystem[currentPath] || [];
    items.forEach(function (item) {
      const element = document.createElement("div");
      element.className = "fs-item";
      element.dataset.type = item.type;
      element.dataset.name = item.name;
      element.title = item.type === "folder" ? "Double-click to open " + item.name : item.name;

      const icon = document.createElement("span");
      icon.className = "fs-icon " + (item.type === "folder" ? "folder" : "file");

      const name = document.createElement("span");
      name.textContent = item.name;

      element.appendChild(icon);
      element.appendChild(name);

      if (item.type === "folder") {
        element.addEventListener("dblclick", function () {
          currentPath = childPath(currentPath, item.name);
          renderFiles();
        });
      }

      filesList.appendChild(element);
    });
  }

  filesUp.addEventListener("click", function () {
    if (currentPath !== "/") {
      currentPath = parentPath(currentPath);
      renderFiles();
    }
  });

  renderFiles();

  const STORAGE_KEY = "ubuntu-desktop-notepad-tabs-v1";
  const tabsElement = document.getElementById("tabs");
  const editor = document.getElementById("editor");
  const newTabButton = document.getElementById("new-tab");

  let noteState = {
    activeId: null,
    tabs: []
  };

  function makeId() {
    return "tab-" + Date.now() + "-" + Math.random().toString(36).slice(2, 8);
  }

  function defaultTab(number) {
    return {
      id: makeId(),
      title: "Untitled " + number,
      content: ""
    };
  }

  function saveNotes() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(noteState));
  }

  function loadNotes() {
    try {
      const saved = JSON.parse(localStorage.getItem(STORAGE_KEY));
      if (saved && Array.isArray(saved.tabs) && saved.tabs.length) {
        noteState.tabs = saved.tabs.filter(function (tab) {
          return tab && typeof tab.id === "string" && typeof tab.content === "string";
        }).map(function (tab, index) {
          return {
            id: tab.id,
            title: typeof tab.title === "string" ? tab.title : "Untitled " + (index + 1),
            content: tab.content
          };
        });

        if (noteState.tabs.length) {
          noteState.activeId = noteState.tabs.some(tab => tab.id === saved.activeId)
            ? saved.activeId
            : noteState.tabs[0].id;
          return;
        }
      }
    } catch (error) {
      /* Invalid saved data is replaced by a clean document. */
    }

    const first = defaultTab(1);
    noteState = { activeId: first.id, tabs: [first] };
    saveNotes();
  }

  function activeTab() {
    return noteState.tabs.find(tab => tab.id === noteState.activeId);
  }

  function renderTabs() {
    tabsElement.innerHTML = "";
    noteState.tabs.forEach(function (tab) {
      const button = document.createElement("button");
      button.type = "button";
      button.className = "tab" + (tab.id === noteState.activeId ? " active" : "");
      button.textContent = tab.title;
      button.title = tab.title;
      button.dataset.tabId = tab.id;
      button.addEventListener("click", function () {
        const current = activeTab();
        if (current) current.content = editor.value;
        noteState.activeId = tab.id;
        saveNotes();
        renderTabs();
        editor.value = activeTab().content;
        editor.focus();
      });
      tabsElement.appendChild(button);
    });

    const activeButton = tabsElement.querySelector(".tab.active");
    if (activeButton) activeButton.scrollIntoView({ block: "nearest", inline: "nearest" });
  }

  newTabButton.addEventListener("click", function () {
    const current = activeTab();
    if (current) current.content = editor.value;

    const tab = defaultTab(noteState.tabs.length + 1);
    noteState.tabs.push(tab);
    noteState.activeId = tab.id;
    saveNotes();
    renderTabs();
    editor.value = "";
    editor.focus();
  });

  editor.addEventListener("input", function () {
    const current = activeTab();
    if (current) {
      current.content = editor.value;
      saveNotes();
    }
  });

  loadNotes();
  renderTabs();
  editor.value = activeTab().content;

  function updateClock() {
    const now = new Date();
    document.getElementById("clock").textContent = now.toLocaleTimeString([], {
      hour: "2-digit",
      minute: "2-digit"
    });
  }

  updateClock();
  setInterval(updateClock, 30000);
})();
</script>
</body>
</html>
